<template>
  <div>
    <h3 class="page-title">路径管理</h3>
    <el-button type="primary" size="small" @click="showDialog = true" class="mb-10">新建路径</el-button>
    <el-table :data="paths" stripe v-loading="loading">
      <el-table-column prop="id" label="ID" width="60" />
      <el-table-column prop="title" label="标题" />
      <el-table-column prop="difficulty" label="难度" width="80">
        <template slot-scope="{row}"><el-tag size="mini">{{ row.difficulty }}</el-tag></template>
      </el-table-column>
      <el-table-column prop="courseCount" label="课程数" width="80" />
      <el-table-column prop="status" label="状态" width="80">
        <template slot-scope="{row}"><el-tag :type="row.status==='PUBLISHED'?'success':'info'" size="mini">{{ row.status }}</el-tag></template>
      </el-table-column>
      <el-table-column label="操作" width="120">
        <template slot-scope="{row}">
          <el-button size="mini" type="danger" @click="handleDelete(row.id)">删除</el-button>
        </template>
      </el-table-column>
    </el-table>

    <el-dialog title="新建路径" :visible.sync="showDialog" width="500px">
      <el-form :model="form" label-width="80px">
        <el-form-item label="标题"><el-input v-model="form.title" /></el-form-item>
        <el-form-item label="描述"><el-input type="textarea" v-model="form.description" /></el-form-item>
        <el-form-item label="难度">
          <el-select v-model="form.difficulty">
            <el-option label="入门" value="BEGINNER" /><el-option label="进阶" value="INTERMEDIATE" /><el-option label="高级" value="ADVANCED" />
          </el-select>
        </el-form-item>
        <el-form-item label="状态">
          <el-select v-model="form.status">
            <el-option label="草稿" value="DRAFT" /><el-option label="发布" value="PUBLISHED" />
          </el-select>
        </el-form-item>
      </el-form>
      <span slot="footer"><el-button @click="showDialog=false">取消</el-button><el-button type="primary" @click="handleCreate">创建</el-button></span>
    </el-dialog>
  </div>
</template>

<script>
import { adminApi } from '../../api';
export default {
  name: 'AdminPaths',
  data() { return { paths: [], loading: true, showDialog: false, form: { title: '', description: '', difficulty: 'BEGINNER', status: 'DRAFT' } }; },
  created() { this.load(); },
  methods: {
    async load() {
      this.loading = true;
      const res = await adminApi.getPaths({ page: 1, pageSize: 100 });
      if (res.code === 200) this.paths = res.data.list || [];
      this.loading = false;
    },
    async handleCreate() {
      await adminApi.createPath(this.form);
      this.$message.success('创建成功');
      this.showDialog = false;
      this.form = { title: '', description: '', difficulty: 'BEGINNER', status: 'DRAFT' };
      this.load();
    },
    async handleDelete(id) {
      await this.$confirm('确认删除？');
      await adminApi.deletePath(id);
      this.$message.success('删除成功');
      this.load();
    }
  }
};
</script>
